mapper.update:
update forum_post
board_id = #{boardId,jdbcType=BIGINT}, user_id = #{userId,jdbcType=BIGINT}, post_title = #{postTitle,jdbcType=VARCHAR}, post_content = #{postContent,jdbcType=LONGVARCHAR}, post_tags = #{postTags,jdbcType=VARCHAR}, post_attach = #{postAttach,jdbcType=VARCHAR}, view_count = #{viewCount,jdbcType=BIGINT}, like_count = #{likeCount,jdbcType=BIGINT}, comment_count = #{commentCount,jdbcType=BIGINT}, collect_count = #{collectCount,jdbcType=BIGINT}, is_top = #{isTop,jdbcType=INTEGER}, is_hot = #{isHot,jdbcType=INTEGER}, audit_status = #{auditStatus,jdbcType=INTEGER}, audit_remark = #{auditRemark,jdbcType=VARCHAR}, is_public = #{isPublic,jdbcType=INTEGER}, update_by = #{updateBy,jdbcType=VARCHAR}, update_time = #{updateTime,jdbcType=TIMESTAMP}, remark = #{remark,jdbcType=VARCHAR},
where id = #{id,jdbcType=BIGINT}

mapper.select:
select p.*, b.board_name, u.nick_name, u.avatar
from forum_post p
left join forum_board b on p.board_id = b.id
left join sys_user u on p.user_id = u.user_id

    and p.board_id = #{boardId}
    and p.post_title like concat('%', #{postTitle}, '%')
    and p.post_tags like concat('%', #{postTags}, '%')
    and p.user_id = #{userId}
    and p.audit_status = #{auditStatus}
    and p.is_top = 1
    and date_format(p.create_time, '%Y-%m-%d') >= #{startTime}
    and date_format(p.create_time, '%Y-%m-%d') <= #{endTime}


        and p.audit_status = 1
        and p.is_public = 1


   or p.user_id = #{userId}


order by p.is_top desc, p.is_hot desc, p.create_time desc

